{"code": "import json
import os

# Load all articles
articles = locals()['var_functions.query_db:2']
if isinstance(articles, str):
    with open(articles, 'r') as f:
        articles = json.load(f)

# Sports identification with better context
sports_articles = []

for article in articles:
    title = article.get('title', '').lower()
    desc = article.get('description', '').lower()

    # Sports indicators with context filtering
    is_sports = False

    # Primary indicators (clear sports)
    primary_terms = ['nba', 'nfl', 'mlb', 'nhl', 'football', 'basketball', 'baseball', 
                     'soccer', 'tennis', 'golf', 'olympics', 'softball', 'championship']

    for term in primary_terms:
        if term in title or term in desc:
            is_sports = True
            break

    # Secondary indicators (need additional verification)
    if not is_sports:
        if 'team' in title or 'team' in desc:
            # Verify it's sports team, not work team
            sports_context = ['game', 'win', 'lose', 'score', 'match', 'player', 'season']
            if any(ctx in desc for ctx in sports_context):
                is_sports = True

        elif 'player' in title or 'player' in desc:
            # Verify it's sports player
            if any(ctx in desc for ctx in ['game', 'team', 'season', 'score']):
                is_sports = True

    if is_sports:
        # Filter out false positives
        if 'rocket' in desc or 'space' in desc or 'technology' in desc or 'software' in desc:
            continue  # Space/tech teams, not sports

        sports_articles.append({
            'title': article.get('title'),
            'description': article.get('description'),
            'desc_length': len(article.get('description', ''))
        })

# Find article with longest description
if sports_articles:
    sports_articles.sort(key=lambda x: x['desc_length'], reverse=True)

    print('Found %d sports articles' % len(sports_articles))
    print('Top 5:')
    for i in range(min(5, len(sports_articles))):
        print('%d. %s (length: %d)' % (i+1, sports_articles[i]['title'], sports_articles[i]['desc_length']))

    answer = sports_articles[0]['title']
else:
    print('No sports articles found')
    answer = 'No sports articles found'

print('__RESULT__:')
print(json.dumps(answer))"}
